  ('judicial-57f41407-moex-00723', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於誠信原則之敘述，何者正確？', '["消滅時效抗辯權之行使，須受誠信原則之限制", "定型化契約之司法控制，非源於誠信原則之思考", "誠信原則僅適用於債之關係", "依誠信原則，契約當事人不負契約約定外之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00724', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '工友乙受僱於甲機關，於機關內傳遞緊急公文時，因時間十分緊迫遂在走廊上奔跑，不慎撞上前來洽公之 丙。關於甲乙丙間之法律關係，下列敘述，何者錯誤？', '["依民法第188條第1項本文之規定，因僱用人利用受僱人擴大其職務活動範圍，故乙若因執行職務，不 法侵害他人之權利者，由僱用人甲代乙負責，乙無須負責", "若甲選任乙及監督其職務之執行，已盡相當之注意或縱加以相當之注意而仍不免發生損害者，甲不負賠 償責任", "即使甲因選任監督乙執行職務已盡相當之注意而免除賠償責任，丙仍得聲請法院斟酌甲與丙之經濟狀 況，令甲為全部或一部之損害賠償", "即使甲並未命乙在走廊奔跑，但該行為與乙執行職務有關，因此甲仍應負民法第188條之僱用人責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00725', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依民法規定，下列關於贈與撤銷之敘述，何者正確？', '["贈與人不得任意撤銷贈與", "在移轉贈與物之權利後，贈與人仍得任意撤銷贈與", "贈與物之權利，若僅為一部移轉，就未移轉之部分，贈與人仍得任意撤銷贈與", "縱使為經公證之贈與，在贈與物權利未移轉前，贈與人仍得任意撤銷贈與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00726', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依現行刑事訴訟法有關傳聞證據之規定，下列敘述何者錯誤？', '["排除之對象擴大為被告以外之人", "以偵查中為判斷傳聞證據之時點", "簡式審判程序不適用傳聞法則", "簡易程序不適用傳聞法則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00727', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '被告或犯罪嫌疑人自拘提或逮捕之時起，應於24小時內到達指定處所。下列何者非法定扣除時間之事由？', '["法院提審之時間", "等候通譯傳譯，未逾6小時之時間", "等候辯護人到場，未逾4小時之時間", "詢問前，請其吸菸緩和情緒之時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00728', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '被告於審判中始終沈默不語，法院應如何處理？', '["探究被告沈默不語之原因為何，如係行使緘默權，應予充分尊重，並停止進行審判程序", "探究被告沈默不語之原因為何，如係行使緘默權，則繼續進行審判程序", "審判作為屬於高權行為，被告有配合及協同之義務，應令其回答問題", "曉諭被告如繼續沈默不語，訴訟結果將對其不利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00729', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '小明因竊盜罪嫌被檢察官起訴，他在法院抗辯說：「我在警察局做筆錄時承認偷錢，是因為警察疲勞訊問， 我才這麼說的。」等語，請問下列敘述何者正確？', '["小明必須負責證明真的有疲勞訊問", "是否疲勞訊問對自白的證據能力並無影響", "被害人必須負責證明小明沒有被疲勞訊問", "檢察官必須負責證明小明沒有被疲勞訊問"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
